import * as React from "react";

type Variant = "primary" | "ghost" | "subtle";

interface ButtonProps
  extends React.ButtonHTMLAttributes<HTMLButtonElement> {
  variant?: Variant;
}

export function Button({
  className = "",
  variant = "primary",
  ...props
}: ButtonProps) {
  const base =
    "inline-flex items-center justify-center rounded-full text-sm font-medium transition-colors focus-visible:outline-none focus-visible:ring-2 focus-visible:ring-offset-2 focus-visible:ring-slate-900/80 disabled:opacity-50 disabled:cursor-not-allowed h-10 px-4";

  const variants: Record<Variant, string> = {
    primary:
      "bg-slate-900 text-slate-50 hover:bg-slate-800 ring-offset-slate-100",
    ghost:
      "bg-transparent text-slate-900 hover:bg-slate-100 ring-offset-slate-100",
    subtle:
      "bg-slate-100 text-slate-900 hover:bg-slate-200 ring-offset-slate-100",
  };

  return (
    <button
      className={[base, variants[variant], className].filter(Boolean).join(" ")}
      {...props}
    />
  );
}

