import * as React from "react";

interface BadgeProps extends React.HTMLAttributes<HTMLSpanElement> {
  tone?: "subtle" | "outline";
}

export function Badge({ className = "", tone = "subtle", ...props }: BadgeProps) {
  const base =
    "inline-flex items-center rounded-full border px-2.5 py-0.5 text-[11px] font-medium uppercase tracking-wide";

  const tones: Record<NonNullable<BadgeProps["tone"]>, string> = {
    subtle: "border-slate-200 bg-slate-50 text-slate-600",
    outline: "border-slate-300 text-slate-700",
  };

  return (
    <span
      className={[base, tones[tone], className].filter(Boolean).join(" ")}
      {...props}
    />
  );
}

